// --- Utility: register dynamic descriptors with global registry ---

func registerFileDescriptor(fd protoreflect.FileDescriptor) error {
	fdProto := protodesc.ToFileDescriptorProto(fd)
	fdSet := &descriptorpb.FileDescriptorSet{
		File: []*descriptorpb.FileDescriptorProto{fdProto},
	}
	_ = fdSet // Could be used for further processing

	// Register with global registry if needed
	_, err := protoregistry.GlobalFiles.FindFileByPath(fd.Path())
	if err != nil {
		// Not yet registered
		newFd, err := protodesc.NewFile(fdProto, nil)
		if err != nil {
			return fmt.Errorf("failed to create file descriptor: %w", err)
		}
		if err := protoregistry.GlobalFiles.RegisterFile(newFd); err != nil {
			return fmt.Errorf("failed to register file: %w", err)
		}
	}
	return nil
}

